// Lógica pura da categorização híbrida — prompt/parse do Gemini, chave do
// Dicionário, teclados inline e parse de callbacks.
// Implementa gstack/plans/categorizacao-hibrida.md.

const LIMIAR_CONFIANCA = 0.8;

/** Prompt de classificação: o Gemini só escolhe entre as categorias ativas. */
function montarPrompt(lancamento, categorias) {
  return [
    "Você categoriza lançamentos financeiros pessoais de um casal brasileiro.",
    `Categorias válidas: ${categorias.join(", ")}.`,
    "Lançamento:",
    `- descrição: ${lancamento.descricao}`,
    `- título: ${lancamento.titulo || "(vazio)"}`,
    `- valor: R$ ${lancamento.valor} (${lancamento.tipo})`,
    `- origem: ${lancamento.origem === "cartao" ? "cartão de crédito" : "conta corrente"}`,
    'Responda APENAS JSON: {"categoria": "<uma das categorias válidas>", "confianca": <0.0 a 1.0>}.',
    "Se nenhuma categoria servir bem, use a mais próxima com confianca baixa.",
  ].join("\n");
}

/**
 * Interpreta a resposta do Gemini. Qualquer problema (não-JSON, categoria fora da
 * lista, confiança inválida) → { valida: false } (degrada para pergunta manual).
 */
function parsearRespostaGemini(texto, categoriasValidas) {
  let obj;
  try {
    obj = JSON.parse(String(texto || "").trim());
  } catch {
    return { valida: false };
  }
  const categoria = String(obj.categoria || "");
  const confianca = Number(obj.confianca);
  if (!categoriasValidas.includes(categoria)) return { valida: false };
  if (Number.isNaN(confianca) || confianca < 0 || confianca > 1) return { valida: false };
  return { valida: true, categoria, confianca, confiante: confianca >= LIMIAR_CONFIANCA };
}

/** Chave para regra nova no Dicionário: Título (conta) ou descrição sem sufixo de parcela (cartão). */
function chaveDicionario(lancamento) {
  if (lancamento.origem === "conta") return String(lancamento.titulo || "").trim();
  return String(lancamento.descricao || "").replace(/ \(\d+\/\d+\)$/, "").trim();
}

/** Resgate de CDB pula o Gemini e pergunta direto a meta (HANDOFF). */
function ehResgateCdb(lancamento) {
  const t = String(lancamento.titulo || "").toUpperCase();
  return t.includes("RESGATE") && t.includes("CDB");
}

/**
 * Teclado inline para pergunta manual. Categorias → `cat|row|nome`;
 * metas ativas → `meta|row|nome` (caminho p/ viagem/hospedagem e CDB).
 * @returns {{inline_keyboard: Array<Array<{text: string, callback_data: string}>>}}
 */
function montarTeclado(row, categorias, metas) {
  const botoes = [
    ...categorias.map((c) => ({ text: c, callback_data: `cat|${row}|${c}` })),
    ...metas.map((m) => ({ text: `🎯 ${m}`, callback_data: `meta|${row}|${m}` })),
  ];
  for (const b of botoes) {
    if (Buffer.byteLength(b.callback_data, "utf-8") > 64) {
      throw new Error(`callback_data excede 64 bytes: ${b.callback_data}`);
    }
  }
  const linhas = [];
  for (let i = 0; i < botoes.length; i += 2) linhas.push(botoes.slice(i, i + 2));
  return { inline_keyboard: linhas };
}

/** Teclado só de metas (caso RESGATE CDB). */
function montarTecladoMetas(row, metas) {
  return montarTeclado(row, [], metas);
}

/** Parse do callback_data. Inválido/desconhecido → null. */
function parsearCallback(data) {
  const m = /^(cat|meta)\|(\d+)\|(.+)$/.exec(String(data || ""));
  if (!m) return null;
  return { tipo: m[1], row: Number(m[2]), nome: m[3] };
}

// Complemento de workflows/src/categorizador.js para a variante Notion: SÓ
// montarTeclado/parsearCallback mudam (o resto — montarPrompt, parsearRespostaGemini,
// chaveDicionario, ehResgateCdb — é reaproveitado sem alteração, concatenado junto).
//
// Por quê um módulo à parte em vez de editar categorizador.js: o original embute o
// NÚMERO DA LINHA do Sheets no callback_data ("cat|row|categoria"). O Notion não tem
// row number — o id da page é um UUID de 32+ caracteres, que somado ao nome da
// categoria estoura o limite de 64 bytes do callback_data do Telegram. Solução: o
// callback_data carrega o id da page (sem hífens) + um ÍNDICE na lista de categorias/
// metas ATIVAS, em vez do nome. Quem recebe o clique (aplicar-categoria) precisa
// reconsultar Categorias/Metas com o MESMO filtro+ordenação (Nome ascendente — ver
// notion-map.js) usado para montar o teclado, para o índice apontar pro item certo.
// categorizador.js (Sheets) fica intocado — o bot do Marcelo não é afetado.

/** IDs do Notion vêm com hífen da API; sem hífen cabe mais no callback_data. */
function semHifen(pageId) {
  return String(pageId || "").replace(/-/g, "");
}

/**
 * @param {string} pageId id da page do Lançamento (com ou sem hífen — normalizado aqui)
 * @param {string[]} categorias ativas, MESMA ordem usada por quem chama (ordenar por Nome)
 * @param {string[]} metas ativas, mesma regra
 */
function montarTecladoNotion(pageId, categorias, metas) {
  const id = semHifen(pageId);
  const botoes = [
    ...categorias.map((c, i) => ({ text: c, callback_data: `cat|${id}|${i}` })),
    ...metas.map((m, i) => ({ text: `🎯 ${m}`, callback_data: `meta|${id}|${i}` })),
  ];
  for (const b of botoes) {
    if (Buffer.byteLength(b.callback_data, "utf-8") > 64) {
      throw new Error(`callback_data excede 64 bytes: ${b.callback_data}`);
    }
  }
  const linhas = [];
  for (let i = 0; i < botoes.length; i += 2) linhas.push(botoes.slice(i, i + 2));
  return { inline_keyboard: linhas };
}

/** Teclado só de metas (caso RESGATE CDB) — mesma convenção do original. */
function montarTecladoMetasNotion(pageId, metas) {
  return montarTecladoNotion(pageId, [], metas);
}

/** Parse do callback_data no formato Notion (id sem hífen + índice numérico). */
function parsearCallbackNotion(data) {
  const m = /^(cat|meta)\|([a-f0-9]{32})\|(\d+)$/.exec(String(data || ""));
  if (!m) return null;
  return { tipo: m[1], pageId: m[2], indice: Number(m[3]) };
}

// Mapeamento puro entre o shape "flat" usado pela lógica de negócio reaproveitada de
// workflows/src/*.js (parser-cartao, parser-conta, dashboard, rateio, ...) e o formato
// de properties da API do Notion (POST /v1/pages, POST /v1/databases/{id}/query).
// Sem I/O — só transformação de dados. Concatenado nos Code nodes do n8n junto com
// os módulos puros originais (ver scripts/gerar-workflow-*-notion.js).
// Implementa a Fase A de gstack (schema em workflows-harumi/README... ver plano da branch).

/** "DD/MM/YYYY" ou "YYYY-MM-DD" → "YYYY-MM-DD" (Notion exige ISO); inválido/vazio → null. */
function paraIso(data) {
  if (data === null || data === undefined || data === "") return null;
  const s = String(data).trim();
  let m;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[1]}-${m[2]}-${m[3]}`;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

/**
 * Texto plano de uma property title/rich_text do Notion. As demais funções de
 * leitura (paraObjeto*) devolvem "YYYY-MM-DD" para datas — mesDe()/normalizarData()
 * em workflows/src/*.js já aceitam esse formato ISO nativamente, então nenhuma
 * conversão adicional é necessária na leitura (só na escrita, via paraIso).
 */
function textoDe(prop) {
  if (!prop) return "";
  const arr = prop.title || prop.rich_text || [];
  return arr.map((t) => t.plain_text || "").join("");
}

const richText = (s) => (s ? [{ text: { content: String(s).slice(0, 2000) } }] : []);
const selectOrNull = (s) => (s ? { select: { name: String(s) } } : { select: null });
const dateOrNull = (isoOuBr) => {
  const iso = paraIso(isoOuBr);
  return iso ? { date: { start: iso } } : { date: null };
};

// ─── Lançamentos ────────────────────────────────────────────────────────────

/** Page do Notion (results[i] de um query em Lançamentos) → objeto flat esperado pelos parsers/dashboard. */
function paraObjetoLancamento(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    data_competencia: (p["Data Competência"] && p["Data Competência"].date && p["Data Competência"].date.start) || "",
    data_original: (p["Data Original"] && p["Data Original"].date && p["Data Original"].date.start) || "",
    descricao: textoDe(p["Descrição"]),
    titulo: "",
    valor: (p["Valor"] && p["Valor"].number) || 0,
    categoria: (p["Categoria"] && p["Categoria"].select && p["Categoria"].select.name) || "",
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    id_meta: textoDe(p["Meta"]),
  };
}

/** Objeto flat (saída do parser-cartao/parser-conta) → properties para criar a page no Notion. */
function propsDeLancamento(l) {
  return {
    "Descrição": { title: richText(l.descricao || l.titulo || "(sem descrição)") },
    "Valor": { number: Number(l.valor) || 0 },
    "Categoria": selectOrNull(l.categoria),
    "Tipo": selectOrNull(l.tipo),
    "Origem": selectOrNull(l.origem),
    "Status": selectOrNull(l.status),
    "Meta": { rich_text: richText(l.id_meta) },
    "Data Competência": dateOrNull(l.data_competencia),
    "Data Original": dateOrNull(l.data_original),
  };
}

/** Update parcial (PATCH) de um Lançamento: só Categoria+Meta — não toca nas demais properties. */
function propsCategoriaEMeta(categoria, idMeta) {
  return { "Categoria": selectOrNull(categoria), "Meta": { rich_text: richText(idMeta) } };
}

// ─── Dicionário ─────────────────────────────────────────────────────────────

function paraObjetoDicionario(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    descricao_original: textoDe(p["Descrição Original"]),
    categoria_mapeada: (p["Categoria Mapeada"] && p["Categoria Mapeada"].select && p["Categoria Mapeada"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

/** Dicionário lido vira { chave, categoria } (contrato de parser-cartao.categorizar / parser-conta). */
function paraDicionarioChaveCategoria(objetosDicionario) {
  return objetosDicionario.map((d) => ({ chave: d.descricao_original, categoria: d.categoria_mapeada }));
}

function propsDeDicionario(d) {
  // Criado Em nunca fica vazio: cai no dia de hoje se d.criado_em não vier preenchido.
  const criadoEm = paraIso(d.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Descrição Original": { title: richText(d.descricao_original || "(vazio)") },
    "Categoria Mapeada": selectOrNull(d.categoria_mapeada),
    "Origem": selectOrNull(d.origem),
    "Criado Em": { date: { start: criadoEm } },
  };
}

// ─── Categorias ─────────────────────────────────────────────────────────────

function paraObjetoCategoria(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    ativo: !!(p["Ativo"] && p["Ativo"].checkbox),
  };
}

function propsDeCategoria(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Tipo": selectOrNull(c.tipo),
    "Ativo": { checkbox: !!c.ativo },
  };
}

// ─── Metas ──────────────────────────────────────────────────────────────────
// Prazo fica RICH_TEXT (não Date): metas.js aceita "AAAA-MM" (sem dia) além de
// "AAAA-MM-DD" — um Date do Notion exige dia, então forçaria uma escolha arbitrária
// (dia 1? último dia?) que a lógica pura nunca precisou fazer. Texto preserva o
// valor exatamente como o usuário digitou em /novameta.

function paraObjetoMeta(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    orcamento_total: (p["Orçamento Total"] && p["Orçamento Total"].number) || 0,
    valor_acumulado: (p["Valor Acumulado"] && p["Valor Acumulado"].number) || 0,
    prazo: textoDe(p["Prazo"]),
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

function propsDeMeta(m) {
  const criadoEm = paraIso(m.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Nome": { title: richText(m.nome || "(sem nome)") },
    "Orçamento Total": { number: Number(m.orcamento_total) || 0 },
    "Valor Acumulado": { number: Number(m.valor_acumulado) || 0 },
    "Prazo": { rich_text: richText(m.prazo) },
    "Status": selectOrNull(m.status),
    "Criado Em": { date: { start: criadoEm } },
  };
}

/** Update parcial: só o cache de progresso (nunca fonte da verdade — ver metas.js). */
function propsValorAcumulado(valor) {
  return { "Valor Acumulado": { number: Number(valor) || 0 } };
}

/** Update parcial: só o Status (ex.: encerrar uma meta). */
function propsStatus(status) {
  return { "Status": selectOrNull(status) };
}

// ─── Contas Fixas ───────────────────────────────────────────────────────────
// Dia Vencimento fica RICH_TEXT (não Number): lembretes.js aceita tanto um dia
// numérico (1–31) quanto o literal "sexta-feira" (contas semanais) — um Number
// do Notion não representaria essa segunda forma.

function paraObjetoContaFixa(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    dia_vencimento: textoDe(p["Dia Vencimento"]),
    valor_esperado: (p["Valor Esperado"] && p["Valor Esperado"].number) || 0,
    // string "sim"/"não": lembretes.js/relatorio.js comparam com essa convenção
    // (normalizar(f.ativo) === "sim"), herdada do Sheets — o checkbox boolean do
    // Notion é traduzido aqui pra não precisar tocar nos dois arquivos compartilhados.
    ativo: (p["Ativo"] && p["Ativo"].checkbox) ? "sim" : "não",
  };
}

function propsDeContaFixa(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Dia Vencimento": { rich_text: richText(c.dia_vencimento) },
    "Valor Esperado": { number: Number(c.valor_esperado) || 0 },
    "Ativo": { checkbox: String(c.ativo).trim().toLowerCase() === "sim" },
  };
}

// ─── Dashboard Mensal ───────────────────────────────────────────────────────

function paraObjetoDashboardMensal(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    mes: textoDe(p["Mês"]),
    saidas: (p["Saídas"] && p["Saídas"].number) || 0,
    entradas: (p["Entradas"] && p["Entradas"].number) || 0,
    saldo: (p["Saldo"] && p["Saldo"].number) || 0,
    metas_ativas: (p["Metas Ativas"] && p["Metas Ativas"].number) || 0,
    gerado_em: (p["Gerado Em"] && p["Gerado Em"].date && p["Gerado Em"].date.start) || "",
  };
}

/** "MM/YYYY" → YYYYMM (número). O título "MM/YYYY" não ordena cronologicamente como
 * texto ("01/2027" vem antes de "12/2026" alfabeticamente) — esta é a coluna de apoio
 * usada pela view "Mais recentes" (SORT BY "Mês Ordinal" DESC). */
function mesOrdinal(mesMMYYYY) {
  const m = /^(\d{2})\/(\d{4})$/.exec(String(mesMMYYYY || "").trim());
  return m ? Number(m[2]) * 100 + Number(m[1]) : 0;
}

function propsDeDashboardMensal(d) {
  return {
    "Mês": { title: richText(d.mes) },
    "Mês Ordinal": { number: mesOrdinal(d.mes) },
    "Saídas": { number: Number(d.saidas) || 0 },
    "Entradas": { number: Number(d.entradas) || 0 },
    "Saldo": { number: Number(d.saldo) || 0 },
    "Metas Ativas": { number: Number(d.metasAtivas) || 0 },
    "Gerado Em": { date: { start: d.geradoEm || new Date().toISOString() } },
  };
}

// ─── Config ─────────────────────────────────────────────────────────────────

function paraObjetoConfig(page) {
  const p = (page && page.properties) || {};
  return { _id: page && page.id, chave: textoDe(p["Chave"]), valor: textoDe(p["Valor"]) };
}

function propsDeConfig(c) {
  return {
    "Chave": { title: richText(c.chave || "(sem chave)") },
    "Valor": { rich_text: richText(c.valor) },
  };
}

// ─── Log ────────────────────────────────────────────────────────────────────

/** Necessário a partir da Fase B: categorizacao-hibrida lê o Log p/ não perguntar 2x. */
function paraObjetoLog(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    timestamp: (p["Timestamp"] && p["Timestamp"].date && p["Timestamp"].date.start) || "",
    acao: textoDe(p["Ação"]),
    entidade: textoDe(p["Entidade"]),
    valor_anterior: textoDe(p["Valor Anterior"]),
    valor_novo: textoDe(p["Valor Novo"]),
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
  };
}

function propsDeLog(l) {
  const registro = `${l.acao || ""} — ${l.entidade || ""}`.trim();
  return {
    "Registro": { title: richText(registro || "log") },
    "Timestamp": { date: { start: l.timestamp || new Date().toISOString() } },
    "Ação": { rich_text: richText(l.acao) },
    "Entidade": { rich_text: richText(l.entidade) },
    "Valor Anterior": { rich_text: richText(l.valor_anterior) },
    "Valor Novo": { rich_text: richText(l.valor_novo) },
    "Origem": selectOrNull(l.origem),
  };
}


// ── Glue: valida o callback (id+índice), busca a page e prepara o update ──
const entrada = $('Início').first().json;
const cb = parsearCallbackNotion(entrada.data);
if (!cb) return [{ json: { acao: 'recusar', aviso: 'Botão inválido ou expirado.' } }];

let paginaLancamento;
try {
  paginaLancamento = await HELPERS.httpRequest({
    method: 'GET', url: `https://api.notion.com/v1/pages/${cb.pageId}`, headers: notionHeaders(), json: true,
  });
} catch (e) {
  return [{ json: { acao: 'recusar', aviso: 'Lançamento não encontrado.' } }];
}
const linha = paraObjetoLancamento(paginaLancamento);
if (String(linha.categoria || '').trim() !== '') {
  return [{ json: { acao: 'recusar', aviso: 'Já categorizado: ' + linha.categoria } }];
}

// MESMO filtro+ordenação de categorizacao-hibrida — o índice do callback_data
// só aponta pro item certo se a lista aqui bater com a de quando o teclado foi montado.
const categoriasAtivas = await notionQueryAll($env.NOTION_DB_CATEGORIAS,
  { property: 'Ativo', checkbox: { equals: true } }, [{ property: 'Nome', direction: 'ascending' }]);
const categorias = categoriasAtivas.map(paraObjetoCategoria).map((c) => c.nome);
const metas = []; // Fase C adiciona a database Metas no Notion

const agora = new Date().toISOString();
let categoria, idMeta = '', regra = null;
if (cb.tipo === 'meta') {
  const nomeMeta = metas[cb.indice];
  if (!nomeMeta) return [{ json: { acao: 'recusar', aviso: 'Meta não está mais ativa.' } }];
  categoria = 'Meta: ' + nomeMeta;
  idMeta = nomeMeta;
} else {
  const nomeCategoria = categorias[cb.indice];
  if (!nomeCategoria) return [{ json: { acao: 'recusar', aviso: 'Categoria não está mais ativa — a lista pode ter mudado, tente categorizar de novo.' } }];
  categoria = nomeCategoria;
  regra = { descricao_original: chaveDicionario(linha), categoria_mapeada: categoria,
    origem: linha.origem, criado_em: agora.slice(0, 10) };
}
const logs = [{ timestamp: agora, acao: 'categoria_aplicada_manual', entidade: 'Lançamentos',
  valor_anterior: 'page=' + cb.pageId, valor_novo: categoria + ' ← ' + linha.descricao, origem: 'aplicar-categoria' }];
if (regra) logs.push({ timestamp: agora, acao: 'regra_adicionada', entidade: 'dicionario',
  valor_anterior: '', valor_novo: regra.descricao_original + ' → ' + categoria, origem: 'aplicar-categoria' });
return [{ json: { acao: 'aplicar', pageId: cb.pageId, categoria, id_meta: idMeta, regra, logs,
  texto_edit: '✅ ' + linha.descricao + ' → ' + categoria } }];

// ── Notion: HTTP cru + paginação (this.helpers vem do runtime do Code node) ──
const NOTION_TOKEN = $env.NOTION_TOKEN;
const NOTION_VERSION = $env.NOTION_VERSION || '2022-06-28';
const HELPERS = this.helpers;
function notionHeaders() {
  return { Authorization: `Bearer ${NOTION_TOKEN}`, 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' };
}
async function notionQueryAll(databaseId, filter, sorts) {
  let results = [];
  let cursor;
  do {
    const body = { page_size: 100 };
    if (filter) body.filter = filter;
    if (sorts) body.sorts = sorts;
    if (cursor) body.start_cursor = cursor;
    const resp = await HELPERS.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${databaseId}/query`,
      headers: notionHeaders(),
      body,
      json: true,
    });
    results = results.concat(resp.results || []);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
  return results;
}
async function notionCreatePage(databaseId, properties) {
  return HELPERS.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: notionHeaders(),
    body: { parent: { database_id: databaseId }, properties },
    json: true,
  });
}
async function notionUpdatePage(pageId, properties) {
  return HELPERS.httpRequest({
    method: 'PATCH',
